demands = [0, 10, 10, 35, 141, 71, 606, 505, 505, 707, 530, 404, 404, 808, 202, 606, 252, 707, 379, 252, 1010, 530, 606, 606, 808, 404, 379, 227, 202, 202, 530, 404, 808, 177, 808, 808, 707, 606, 151, 379, 530, 530, 530, 404, 404, 606, 808, 202, 404, 10, 15, 5, 10, 10, 5, 10, 5, 5, 5, 5, 5, 10, 227, 177, 353, 202, 808, 530, 404, 404, 35, 530, 353, 353, 252, 177, 227, 106, 106, 404, 404, 35, 126, 404, 606, 404, 379, 530, 353, 606, 808, 505, 202, 303, 808, 606, 404, 353, 10, 353, 177, 530, 202, 303, 606, 808, 404, 202, 404, 404, 379, 126, 353, 10, 10, 10, 10, 5, 71, 35, 10, 606, 202, 606, 202, 202, 530, 530, 530, 177, 177, 530, 353, 151, 5, 20, 530, 353, 5, 151]  # Demanda de cada cliente, el índice 0 es el depósito
vehicle_capacity = 7000  # Capacidad máxima del vehículo
n_ants = 10  # Número de hormigas
n_generations = 100  # Número de iteraciones
alpha = 1  # Influencia de las feromonas
beta = 5   # Influencia de la heurística (inverso de la distancia)
rho = 0.5  # Tasa de evaporación de feromonas
pheromone_initial = 1.0  # Valor inicial de feromonas en cada camino

# Inicialización de feromonas
pheromones = np.ones(distances.shape) * pheromone_initial  # Esto asegura que 'pheromones' se inicializa globalmente

# Heurística basada en la distancia (cuanto más corta, mejor)
heuristic = 1 / (distances + 1e-10)  # Evitar divisiones por cero

# Función para dividir una ruta en subrutas según la capacidad del vehículo
def split_route(route):
    subroutes = []
    current_subroute = [0]  # Comenzar en el depósito
    current_load = 0

    for client in route:
        if current_load + demands[client] <= vehicle_capacity:
            current_subroute.append(client)
            current_load += demands[client]
        else:
            # Completar la subruta actual regresando al depósito
            current_subroute.append(0)
            subroutes.append(current_subroute)
            # Iniciar una nueva subruta
            current_subroute = [0, client]
            current_load = demands[client]
    
    # Añadir la última subruta si es necesario
    current_subroute.append(0)
    subroutes.append(current_subroute)

    return subroutes

# Función para calcular la distancia total de una ruta dividida en subrutas
def calculate_total_distance(subroutes):
    total_distance = 0
    for subroute in subroutes:
        for i in range(len(subroute) - 1):
            total_distance += distances[subroute[i]][subroute[i + 1]]
    return total_distance

# Función para construir una solución de una hormiga
def construct_solution():
    n_clients = len(demands) - 1
    unvisited = list(range(1, n_clients + 1))  # Clientes que no han sido visitados
    route = []
    current_node = 0  # Comenzar en el depósito

    while unvisited:
        probabilities = []
        for client in unvisited:
            pheromone_value = pheromones[current_node][client] ** alpha
            heuristic_value = heuristic[current_node][client] ** beta
            probabilities.append(pheromone_value * heuristic_value)
        
        probabilities = np.array(probabilities) / np.sum(probabilities)
        
        # Elegir el siguiente cliente basado en las probabilidades
        next_node = np.random.choice(unvisited, p=probabilities)
        route.append(next_node)
        unvisited.remove(next_node)
        current_node = next_node
    
    return route

# Función principal del algoritmo de colonia de hormigas
def ant_colony_optimization():
    global pheromones  # Asegurar que accedemos a la variable global 'pheromones'
    best_route = None
    best_distance = float('inf')

    for generation in range(n_generations):
        all_routes = []
        all_distances = []

        # Cada hormiga construye una solución
        for _ in range(n_ants):
            route = construct_solution()
            subroutes = split_route(route)
            total_distance = calculate_total_distance(subroutes)

            all_routes.append(route)
            all_distances.append(total_distance)

            # Guardar la mejor solución
            if total_distance < best_distance:
                best_route = subroutes
                best_distance = total_distance

        # Actualización de feromonas (evaporación y refuerzo)
        pheromones *= (1 - rho)  # Evaporación
        for i in range(n_ants):
            route = all_routes[i]
            distance = all_distances[i]
            # Refuerzo de feromonas basado en la calidad de la solución
            for j in range(len(route) - 1):
                pheromones[route[j]][route[j + 1]] += 1.0 / distance

        print(f"Generación {generation + 1}, Mejor distancia: {best_distance}")

    return best_route, best_distance

# Ejecutar el ACO para CVRP
best_route, best_distance = ant_colony_optimization()
print(f"Mejor ruta: {best_route}")
print(f"Distancia total: {best_distance}")
